content:
{
  "sentences": [
    {
      "text": "那個人長得很高，而且很瘦。",
      "pinyin": "Nà ge rén zhǎng de hěn gāo, érqiě hěn shòu.",
      "pinyin_numeric": "na4 ge4 ren2 zhang3 de5 hen3 gao1, er2 qie3 hen3 shou4.",
      "translation_en": "That person is very tall and also very thin.",
      "translation_ko": "그 사람은 키가 매우 크고, 또한 매우 날씬합니다."
    },
    {
      "text": "她長得很漂亮，眼睛很大。",
      "pinyin": "Tā zhǎng de hěn piàoliang, yǎnjīng hěn dà.",
      "pinyin_numeric": "ta1 zhang3 de5 hen3 piao4 liang5, yan3 jing1 hen3 da4.",
      "translation_en": "She is very pretty, and her eyes are big.",
      "translation_ko": "그녀는 매우 예쁘고, 눈이 큽니다."
    },
    {
      "text": "他看起來很年輕，可是已經三十歲了。",
      "pinyin": "Tā kàn qǐlái hěn niánqīng, kěshì yǐjīng sān shí suì le.",
      "pinyin_numeric": "ta1 kan4 qi3 lai2 hen3 nian2 qing1, ke3 shi4 yi3 jing1 san1 shi2 sui4 le5.",
      "translation_en": "He looks very young, but he is already thirty years old.",
      "translation_ko": "그는 매우 젊어 보이지만, 벌써 서른 살입니다."
    },
    {
      "text": "我哥哥長得很帥，而且個性很幽默。",
      "pinyin": "Wǒ gēge zhǎng de hěn shuài, érqiě gèxìng hěn yōumò.",
      "pinyin_numeric": "wo3 ge1 ge5 zhang3 de5 hen3 shuai4, er2 qie3 ge4 xing4 hen3 you1 mo4.",
      "translation_en": "My older brother is very handsome, and his personality is very humorous.",
      "translation_ko": "제 오빠는 매우 잘생겼고, 성격도 매우 유머러스합니다."
    },
    {
      "text": "那個女生看起來很害羞，不太說話。",
      "pinyin": "Nà ge nǚshēng kàn qǐlái hěn hàixiū, bú tài shuōhuà.",
      "pinyin_numeric": "na4 ge4 nü3 sheng1 kan4 qi3 lai2 hen3 hai4 xiu1, bu2 tai4 shuo1 hua4.",
      "translation_en": "That girl looks very shy and doesn't talk much.",
      "translation_ko": "그 여학생은 매우 수줍어 보이고, 말을 많이 하지 않습니다."
    },
    {
      "text": "他長得不高，可是很聰明。",
      "pinyin": "Tā zhǎng de bù gāo, kěshì hěn cōngmíng.",
      "pinyin_numeric": "ta1 zhang3 de5 bu4 gao1, ke3 shi4 hen3 cong1 ming2.",
      "translation_en": "He is not tall, but he is very smart.",
      "translation_ko": "그는 키가 크지 않지만, 매우 똑똑합니다."
    },
    {
      "text": "我朋友長得很可愛，而且很友善。",
      "pinyin": "Wǒ péngyou zhǎng de hěn kě'ài, érqiě hěn yǒushàn.",
      "pinyin_numeric": "wo3 peng2 you5 zhang3 de5 hen3 ke3 ai4, er2 qie3 hen3 you3 shan4.",
      "translation_en": "My friend is very cute and also very friendly.",
      "translation_ko": "제 친구는 매우 귀엽고, 또한 매우 친절합니다."
    },
    {
      "text": "那個人看起來很認真，一直在寫東西。",
      "pinyin": "Nà ge rén kàn qǐlái hěn rènzhēn, yìzhí zài xiě dōngxi.",
      "pinyin_numeric": "na4 ge4 ren2 kan4 qi3 lai2 hen3 ren4 zhen1, yi4 zhi2 zai4 xie3 dong1 xi5.",
      "translation_en": "That person looks very serious and is always writing something.",
      "translation_ko": "그 사람은 매우 진지해 보이고, 계속 무언가를 쓰고 있습니다."
    },
    {
      "text": "她長得很瘦，而且頭髮很長。",
      "pinyin": "Tā zhǎng de hěn shòu, érqiě tóufa hěn cháng.",
      "pinyin_numeric": "ta1 zhang3 de5 hen3 shou4, er2 qie3 tou2 fa5 hen3 chang2.",
      "translation_en": "She is very thin, and her hair is very long.",
      "translation_ko": "그녀는 매우 날씬하고, 머리카락이 매우 깁니다."
    },
    {
      "text": "他看起來很活潑，喜歡跟朋友聊天。",
      "pinyin": "Tā kàn qǐlái hěn huópō, xǐhuān gēn péngyou liáotiān.",
      "pinyin_numeric": "ta1 kan4 qi3 lai2 hen3 huo2 po1, xi3 huan1 gen1 peng2 you5 liao2 tian1.",
      "translation_en": "He looks very lively and likes to chat with friends.",
      "translation_ko": "그는 매우 활발해 보이고, 친구들과 이야기하는 것을 좋아합니다."
    }
  ]
}
